function readStoredJson<T>(key: string, defaultValue: T): T {
  try {
    const val = localStorage.getItem(key);
    return val ? JSON.parse(val) : defaultValue;
  } catch (e) {
    return defaultValue;
  }
}

const parseBoldText = (text: string) => {
  const parts = text.split(/(\*\*.*?\*\*)/g);
  return parts.map((part, i) => {
    if (part.startsWith("**") && part.endsWith("**")) {
      return (
        <strong key={i} className="font-extrabold text-indigo-300">
          {part.slice(2, -2)}
        </strong>
      );
    }
    return part;
  });
};

const renderMarkdownText = (text: string) => {
  if (!text) return null;
  const lines = text.split("\n");
  return (
    <div className="space-y-2 text-left text-sm text-slate-100 leading-relaxed font-sans mt-3">
      {lines.map((line, idx) => {
        // Heading 3
        if (line.startsWith("### ")) {
          return (
            <h4
              key={idx}
              className="text-sm font-bold text-slate-100 mt-4 border-l-2 border-indigo-500 pl-2"
            >
              {line.replace("### ", "")}
            </h4>
          );
        }
        // Heading 2
        if (line.startsWith("## ")) {
          return (
            <h3
              key={idx}
              className="text-base font-black text-transparent bg-gradient-to-r from-indigo-300 to-indigo-100 bg-clip-text mt-5"
            >
              {line.replace("## ", "")}
            </h3>
          );
        }
        // Heading 1
        if (line.startsWith("# ")) {
          return (
            <h2 key={idx} className="text-lg font-black text-slate-100 mt-6">
              {line.replace("# ", "")}
            </h2>
          );
        }
        // Bullet points
        if (
          String(line || "")
            .trim()
            .startsWith("- ") ||
          String(line || "")
            .trim()
            .startsWith("* ")
        ) {
          const stripped = line.replace(/^\s*[-*]\s+/, "");
          return (
            <div
              key={idx}
              className="flex items-start gap-2 ml-4 my-1.5"
              style={{ minWidth: 0 }}
            >
              <span className="w-1.5 h-1.5 bg-indigo-400 rounded-full mt-2 shrink-0 animate-pulse" />
              <p className="text-slate-200 text-xs flex-1">
                {parseBoldText(stripped)}
              </p>
            </div>
          );
        }
        // General text
        if (String(line || "").trim().length > 0) {
          return (
            <p key={idx} className="text-slate-300 text-xs my-1">
              {parseBoldText(line)}
            </p>
          );
        }
        return <div key={idx} className="h-1" />;
      })}
    </div>
  );
};

async function fetchGoogleSheetCSV(
  sheetId: string,
  gid: string = "0",
): Promise<string> {
  const urlsToTry = [
    `https://docs.google.com/spreadsheets/d/${sheetId}/export?format=csv&gid=${gid}`,
    `https://docs.google.com/spreadsheets/d/${sheetId}/gviz/tq?tqx=out:csv&gid=${gid}`,
    `https://docs.google.com/spreadsheets/d/${sheetId}/pub?output=csv&gid=${gid}`,
  ];
  let lastError: Error | null = null;

  // 1. Try directly first
  for (const url of urlsToTry) {
    try {
      const res = await fetch(url);
      if (res.ok) {
        const text = await res.text();
        if (
          text &&
          String(text || "").trim().length > 0 &&
          !text.includes("<!DOCTYPE html>")
        ) {
          return text;
        }
      }
    } catch (err: any) {
      lastError = err;
    }
  }

  // 2. If direct fetches fail, try via CORS proxy
  for (const url of urlsToTry) {
    try {
      const proxyUrl = `https://api.allorigins.win/raw?url=${encodeURIComponent(url)}`;
      const res = await fetch(proxyUrl);
      if (res.ok) {
        const text = await res.text();
        if (
          text &&
          String(text || "").trim().length > 0 &&
          !text.includes("<!DOCTYPE html>")
        ) {
          return text;
        }
      }
    } catch (err: any) {
      lastError = err;
    }
  }

  throw new Error(
    "Access Denied or Sheet not found. Please make sure the Google Sheet share settings are set to 'Anyone with the link can view'.",
  );
}

const getClinicBadgeColor = (clinic: string) => {
  if (!clinic) return "bg-white/5 text-slate-300 border-white/10";
  const lp = clinic.toLowerCase();
  if (lp.includes("dermadent"))
    return "bg-blue-500/10 text-blue-300 border-blue-500/20";
  if (lp.includes("onetouch"))
    return "bg-emerald-500/10 text-emerald-300 border-emerald-500/20";
  if (lp.includes("welltouch"))
    return "bg-rose-500/10 text-rose-300 border-rose-500/20";
  if (lp.includes("newage"))
    return "bg-amber-500/10 text-amber-300 border-amber-500/20";
  return "bg-white/5 text-slate-300 border-white/10";
};

