  const handleKbAiQuery = async () => {
    if (!String(searchQueryKb || "").trim()) {
      toast.error("Please enter a query to ask the AI.");
      return;
    }
    setIsAnsweringKb(true);
    setKbAiAnswer("");
    try {
      let context = "";
      if (knowledgeBaseDocuments.length > 0) {
        context = knowledgeBaseDocuments
          .map((d) => `Document: ${d.name}\nContent:\n${d.content}`)
          .join("\n\n");
        if (context.length > 7000) {
          context = context.substring(0, 7000) + "... (truncated)";
        }
      }
      const res = await fetch("/api/ai-chat", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          message: searchQueryKb,
          knowledgeContext: context,
        }),
      });
      if (!res.ok) {
        throw new Error("Failed to fetch AI response");
      }
      const data = await res.json();
      setKbAiAnswer(data.reply);
      toast.success("AI grounding analysis completed!");
    } catch (err: any) {
      console.error(err);
      toast.error("Failed to get AI response. Check your API configuration.");
    } finally {
      setIsAnsweringKb(false);
    }
  };

  const handleKbFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const extension = file.name.split(".").pop()?.toLowerCase() || "";

    // Generous limit of 4MB for high performance in browser-based Storage
    if (file.size > 4 * 1024 * 1024) {
      toast.error(
        "File size exceeds the 4MB limit for direct browser upload. Consider uploading smaller documents.",
      );
      return;
    }

    // Special Route: PDF Text Extraction Ingestion
    if (extension === "pdf") {
      const pdfReader = new FileReader();
      pdfReader.onload = async (event) => {
        try {
          const arrayBuffer = event.target?.result as ArrayBuffer;
          if (!arrayBuffer) {
            throw new Error("PDF file is empty.");
          }

          toast.loading("Ingesting and extracting text from PDF...", {
            id: "pdf-load",
          });

          let extractedText = "";
          try {
            // Load PDF.js dynamically from high-speed reliable Cloudflare CDN
            if (!(window as any).pdfjsLib) {
              await new Promise<void>((resolve, reject) => {
                const script = document.createElement("script");
                script.src =
                  "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js";
                script.onload = () => resolve();
                script.onerror = () =>
                  reject(new Error("Failed to load PDF extraction engine."));
                document.head.appendChild(script);
              });
            }

            const pdfjsLib = (window as any).pdfjsLib;
            pdfjsLib.GlobalWorkerOptions.workerSrc =
              "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js";

            const loadingTask = pdfjsLib.getDocument({
              data: new Uint8Array(arrayBuffer),
            });
            const pdf = await loadingTask.promise;

            let fullText = "";
            for (let i = 1; i <= pdf.numPages; i++) {
              const page = await pdf.getPage(i);
              const textContent = await page.getTextContent();
              const pageText = textContent.items
                .map((item: any) => item.str)
                .join(" ");
              fullText += `--- Page ${i} ---
${pageText}

`;
            }
            extractedText =
              String(fullText || "").trim() ||
              "No searchable text content found in PDF.";
            toast.success(`Extracted ${pdf.numPages} pages from PDF!`, {
              id: "pdf-load",
            });
          } catch (pdfErr: any) {
            console.error(pdfErr);
            toast.error(
              "Local PDF parsing failed. Uploading as reference binary file.",
              { id: "pdf-load" },
            );

            // Fallback: save as standard binary data URL
            const binaryReader = new FileReader();
            binaryReader.onload = (binEv) => {
              const dataUrl = binEv.target?.result as string;
              const newDoc = {
                id: `kb_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
                name: file.name,
                type: "PDF",
                mimeType: "application/pdf",
                uploadedAt: new Date().toISOString(),
                content: dataUrl,
                size: file.size,
                isBinary: true,
              };
              setKnowledgeBaseDocuments((prev) => [newDoc, ...prev]);
              setSelectedKbDocId(newDoc.id);
            };
            binaryReader.readAsDataURL(file);
            return;
          }

          const newDoc = {
            id: `kb_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
            name: file.name,
            type: "PDF",
            mimeType: "application/pdf",
            uploadedAt: new Date().toISOString(),
            content: extractedText,
            size: file.size,
            isBinary: false, // Successfully extracted to structured text!
          };

          setKnowledgeBaseDocuments((prev) => [newDoc, ...prev]);
          setSelectedKbDocId(newDoc.id);
          toast.success(`"${file.name}" indexed successfully!`);
        } catch (err: any) {
          toast.error("Failed to parse PDF file: " + err.message, {
            id: "pdf-load",
          });
        }
      };
      pdfReader.onerror = () => {
        toast.error("Failed to read the selected PDF file.");
      };
      pdfReader.readAsArrayBuffer(file);
      return;
    }

    // Determine if file is text or binary
    if (extension === "docx") {
      const docxReader = new FileReader();
      docxReader.onload = async (event) => {
        try {
          const arrayBuffer = event.target?.result as ArrayBuffer;
          if (!arrayBuffer) throw new Error("DOCX file is empty.");
          toast.loading("Extracting text from Word document...", {
            id: "docx-load",
          });
          const result = await mammoth.extractRawText({ arrayBuffer });
          const extractedText =
            result.value || "No readable text content found in document.";
          if (result.messages && result.messages.length > 0)
            console.warn(result.messages);
          const newDoc = {
            id: `kb_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
            name: file.name,
            type: "DOCX",
            mimeType:
              "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
            uploadedAt: new Date().toISOString(),
            content: extractedText,
            size: file.size,
            isBinary: false,
          };
          setKnowledgeBaseDocuments((prev) => [newDoc, ...prev]);
          setSelectedKbDocId(newDoc.id);
          toast.success(`"${file.name}" indexed successfully!`, {
            id: "docx-load",
          });
        } catch (err: any) {
          toast.error("Failed to parse Word Document: " + err.message, {
            id: "docx-load",
          });
        }
      };
      docxReader.onerror = () =>
        toast.error("Failed to read the selected DOCX file.");
      docxReader.readAsArrayBuffer(file);
      return;
    }

    const textExtensions = [
      "txt",
      "md",
      "csv",
      "json",
      "xml",
      "html",
      "css",
      "js",
      "ts",
      "svg",
      "yaml",
      "yml",
      "ini",
      "log",
    ];
    const isText =
      file.type.startsWith("text/") ||
      textExtensions.includes(extension) ||
      file.type === "application/json" ||
      file.type === "application/javascript";

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const fileContent = event.target?.result as string;
        if (!fileContent) {
          throw new Error("File is empty.");
        }

        const newDoc = {
          id: `kb_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
          name: file.name,
          type: extension.toUpperCase() || "FILE",
          mimeType: file.type || "application/octet-stream",
          uploadedAt: new Date().toISOString(),
          content: fileContent,
          size: file.size,
          isBinary: !isText,
        };

        setKnowledgeBaseDocuments((prev) => [newDoc, ...prev]);
        setSelectedKbDocId(newDoc.id);
        toast.success(`"${file.name}" uploaded successfully!`);
      } catch (err: any) {
        toast.error("Failed to parse file: " + err.message);
      }
    };

    reader.onerror = () => {
      toast.error("Failed to read the selected file.");
    };

    if (isText) {
      reader.readAsText(file);
    } else {
      reader.readAsDataURL(file);
    }
  };

