  // Dynamic global search matching over all datasets with phone numbers
  const globalSearchResults = useMemo(() => {
    const searchVal = debouncedGlobalSearchInput.trim();
    if (!searchVal) return [];

    const normSearchVal = normalizePhone(searchVal);
    if (!normSearchVal) return [];

    const results: Array<{
      id: string;
      type:
        | "inquiry"
        | "tabby_tamara"
        | "complaint"
        | "client_comm"
        | "case"
        | "request";
      patientName: string;
      phoneNumber: string;
      clinicName: string;
      status: string;
      createdAt: string;
      agentName: string;
      caseRef: string;
      originalItem: any;
    }> = [];

    const isMatched = (phone: string) => {
      const normPhone = normalizePhone(phone);
      if (!normPhone) return false;
      if (normSearchVal.length >= 7) {
        return (
          normPhone.includes(normSearchVal) || normSearchVal.includes(normPhone)
        );
      } else {
        return normPhone.includes(normSearchVal);
      }
    };

    // 1. Inquiries
    (inquiries || []).forEach((item) => {
      if (item.phoneNumber && isMatched(item.phoneNumber)) {
        results.push({
          id: item.id,
          type: "inquiry",
          patientName: item.patientName || "Unknown Patient",
          phoneNumber: item.phoneNumber || "",
          clinicName: item.clinicName || "",
          status: item.status,
          createdAt: item.createdAt,
          agentName: item.agentName,
          caseRef: item.caseRef || item.id.substring(0, 8),
          originalItem: item,
        });
      }
    });

    // 2. Tabby & Tamara Requests
    (tabbyTamaraRequests || []).forEach((item) => {
      if (item.phoneNumber && isMatched(item.phoneNumber)) {
        results.push({
          id: item.id,
          type: "tabby_tamara",
          patientName: item.patientName || "Unknown Patient",
          phoneNumber: item.phoneNumber || "",
          clinicName: item.clinicName || "",
          status: item.status,
          createdAt: item.createdAt,
          agentName: item.agentName,
          caseRef: item.caseRef || item.id.substring(0, 8),
          originalItem: item,
        });
      }
    });

    // 3. Tabby & Tamara Complaints
    (tabbyTamaraComplaints || []).forEach((item) => {
      if (item.phoneNumber && isMatched(item.phoneNumber)) {
        results.push({
          id: item.id,
          type: "complaint",
          patientName: item.patientName || "Unknown Patient",
          phoneNumber: item.phoneNumber || "",
          clinicName: item.clinicName || "",
          status: item.status,
          createdAt: item.createdAt,
          agentName: item.agentName,
          caseRef: item.caseRef || item.id.substring(0, 8),
          originalItem: item,
        });
      }
    });

    // 4. Client Communication Requests
    (clientComms || []).forEach((item) => {
      if (item.phoneNumber && isMatched(item.phoneNumber)) {
        results.push({
          id: item.id,
          type: "client_comm",
          patientName:
            item.patientName || item.notes?.substring(0, 20) || "Client Comm",
          phoneNumber: item.phoneNumber || "",
          clinicName: item.clinicName || "",
          status: item.status,
          createdAt: item.createdAt,
          agentName: item.callCenterAgentName || "System",
          caseRef: item.caseRef || item.id.substring(0, 8),
          originalItem: item,
        });
      }
    });

    // 5. Cases
    (cases || []).forEach((item) => {
      if (item.phoneNumber && isMatched(item.phoneNumber)) {
        results.push({
          id: item.id,
          type: "case",
          patientName: item.patientName || "Unknown Patient",
          phoneNumber: item.phoneNumber || "",
          clinicName: item.branch || "",
          status: "submitted",
          createdAt: item.createdAt,
          agentName: item.agentName,
          caseRef: item.caseRef || item.id.substring(0, 8),
          originalItem: item,
        });
      }
    });

    // 6. Scheduling Requests
    (requests || []).forEach((item: any) => {
      if (item.phoneNumber && isMatched(item.phoneNumber)) {
        results.push({
          id: item.id,
          type: "request",
          patientName: item.agentName || "Agent Work Request",
          phoneNumber: item.phoneNumber,
          clinicName: "",
          status: item.status || "pending",
          createdAt: item.createdAt,
          agentName: item.agentName,
          caseRef: item.id.substring(0, 8),
          originalItem: item,
        });
      }
    });

    return results.sort(
      (a, b) =>
        new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime(),
    );
  }, [
    debouncedGlobalSearchInput,
    inquiries,
    tabbyTamaraRequests,
    tabbyTamaraComplaints,
    clientComms,
    cases,
    requests,
  ]);

