  // Partner Decision (Agree / Decline Swap Request)
  const handlePartnerDecision = (requestId: string, agree: boolean) => {
    if (!currentUser) return;

    const performAction = () => {
      const updated = requests.map((req) => {
        if (req.id === requestId && req.type === "swap") {
          const swapReq = req as SwapRequest;
          if (
            swapReq.swapWithAgent.toLowerCase() ===
              currentUser?.name?.toLowerCase() &&
            swapReq.status === "pending_partner"
          ) {
            const updatedReq = {
              ...swapReq,
              status: agree ? "pending" : "declined_by_partner",
              partnerActionAt: new Date().toISOString(),
            } as SwapRequest;
            // Sync to Firestore
            setDoc(doc(db, "scheduling_requests", req.id), updatedReq).catch(
              (e) => console.error("Partner Decision Error:", e),
            );
            return updatedReq;
          }
        }
        return req;
      });

      setRequests(updated);
      setStorageItem("sched_requests", updated);

      if (agree) {
        toast.success(
          "You have agreed to the swap. The request is now forwarded to Team Leaders for final decision.",
        );
      } else {
        toast.error("You have declined the swap request.");
      }
    };

    if (agree) {
      showConfirm(
        "Accept Swap Request",
        "Are you sure you want to accept this swap? This cannot be undone.",
        "Yes, Accept",
        "bg-emerald-600 hover:bg-emerald-500",
        performAction,
      );
      return;
    }

    performAction();
  };

  const handleBulkTLApproval = (requestIds: string[], approve: boolean) => {
    if (!currentUser || currentUser.role !== "tl") return;

    const idSet = new Set(requestIds);
    const updated = requests.map((req) => {
      if (idSet.has(req.id)) {
        let violation = false;
        let vMsg = "";

        if (req.type === "swap") {
          const v = validateSwapRequest(
            req.date,
            req.shift,
            new Date(req.createdAt),
          );
          if (!v.isValid) {
            violation = true;
            vMsg = v.message || "";
          }
        } else {
          const v = validateAnnualRequest(
            req.startDate,
            new Date(req.createdAt),
          );
          if (!v.isValid) {
            violation = true;
            vMsg = v.message || "";
          }
        }

        const updatedReq = {
          ...req,
          status: (approve ? "approved" : "declined") as
            | "approved"
            | "declined",
          actionBy: currentUser.name,
          actionAt: new Date().toISOString(),
          ruleViolation: violation,
          violationMessage: violation ? vMsg : undefined,
        };
        // Sync to Firestore
        setDoc(doc(db, "scheduling_requests", req.id), updatedReq).catch((e) =>
          console.error("TL Approval Error:", e),
        );
        return updatedReq;
      }
      return req;
    });

    setRequests(updated);
    setStorageItem("sched_requests", updated);
    toast.success(
      `Successfully ${approve ? "approved" : "declined"} ${requestIds.length} requests.`,
    );
  };

  // TL Action (Approve / Decline)
  const handleTLApproval = (requestId: string, approve: boolean) => {
    if (!currentUser || currentUser.role !== "tl") return;

    const updated = requests.map((req) => {
      if (req.id === requestId) {
        // Double check validations before making decision
        let violation = false;
        let vMsg = "";

        if (req.type === "swap") {
          const v = validateSwapRequest(
            req.date,
            req.shift,
            new Date(req.createdAt),
          );
          if (!v.isValid) {
            violation = true;
            vMsg = v.message || "";
          }
        } else {
          const v = validateAnnualRequest(
            req.startDate,
            new Date(req.createdAt),
          );
          if (!v.isValid) {
            violation = true;
            vMsg = v.message || "";
          }
        }

        const updatedReq = {
          ...req,
          status: (approve ? "approved" : "declined") as
            | "approved"
            | "declined",
          actionBy: currentUser.name,
          actionAt: new Date().toISOString(),
          ruleViolation: violation,
          violationMessage: violation ? vMsg : undefined,
        };
        // Sync to Firestore
        setDoc(doc(db, "scheduling_requests", req.id), updatedReq).catch((e) =>
          console.error("TL Approval Error:", e),
        );
        return updatedReq;
      }
      return req;
    });

    setRequests(updated);
    setStorageItem("sched_requests", updated);

    const decidedReq = updated.find((r) => r.id === requestId);
    if (decidedReq) {
      addSystemNotification(
        approve ? " Leave/Swap Approved" : " Leave/Swap Declined",
        approve
          ? `Your ${decidedReq.type === "swap" ? "shift swap" : "annual leave"} request has been approved by ${currentUser.name}.`
          : `Your ${decidedReq.type === "swap" ? "shift swap" : "annual leave"} request was declined by ${currentUser.name}.`,
        "schedule",
        decidedReq.agentName,
        undefined,
        "scheduling_request",
        requestId,
      );
    }
  };

