  // Drag and drop events
  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);

    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      const file = e.dataTransfer.files[0];
      handleScheduleFile(file);
    }
  };

  const handleScheduleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      handleScheduleFile(e.target.files[0]);
    }
  };

  const handleScheduleFile = (file: File) => {
    setUploadError(null);
    setUploadSuccess(null);
    setTempSchedules([]);
    setTempNewAgents([]);

    const reader = new FileReader();
    const isJson = file.name.endsWith(".json");

    if (isJson) {
      reader.onload = (event) => {
        try {
          const text = event.target?.result as string;
          const parsed = JSON.parse(text);
          if (Array.isArray(parsed)) {
            const validShifts = parsed.filter(
              (item) =>
                item &&
                (item.agentName || item.AgentName) &&
                (item.date || item.Date),
            );
            if (validShifts.length > 0) {
              const formatted: ScheduledShift[] = validShifts.map((s) => ({
                id: s.id || `sch_json_${Date.now()}_${Math.random()}`,
                agentName: s.agentName || s.AgentName,
                date: s.date || s.Date,
                shiftLabel:
                  s.shiftLabel ||
                  s.ShiftLabel ||
                  s.shift ||
                  s.Shift ||
                  "07:00 - 16:00",
              }));
              setUploadSuccess(
                `Successfully parsed ${formatted.length} shifts. ${isSuperAdmin ? "Updating system automatically..." : "Review the draft below."}`,
              );
              if (isSuperAdmin) {
                commitSchedulesManual(formatted, [], {});
              } else {
                setTempSchedules(formatted);
                setTempNewAgents([]);
                setTempParsedMeta({});
              }
              return;
            }
          }
          throw new Error("Invalid schedule shift array format in JSON.");
        } catch (e: any) {
          setUploadError(`Failed to parse JSON file: ${e.message}`);
        }
      };
      reader.readAsText(file);
    } else {
      reader.onload = (event) => {
        try {
          const data = new Uint8Array(event.target?.result as ArrayBuffer);
          const workbook = XLSX.read(data, { type: "array" });
          if (!workbook.SheetNames || workbook.SheetNames.length === 0) {
            throw new Error("No worksheets found in this file.");
          }
          const firstSheetName = workbook.SheetNames[0];
          const worksheet = workbook.Sheets[firstSheetName];
          const csvText = XLSX.utils.sheet_to_csv(worksheet);
          if (!csvText || !String(csvText || "").trim()) {
            throw new Error("Could not extract sheet content.");
          }

          const result = parseScheduleCSV(csvText, agentsList);
          if (result.errors.length > 0) {
            setUploadError(`Parsed with warnings/errors: 
${result.errors.slice(0, 5).join("\n")}${
              result.errors.length > 5
                ? `
...and ${result.errors.length - 5} more errors`
                : ""
            }`);
          }

          if (result.schedules.length === 0) {
            if (result.errors.length === 0)
              setUploadError("Could not find any schedule entries to parse.");
          } else {
            setUploadSuccess(
              `Successfully parsed ${result.schedules.length} shifts. ${isSuperAdmin ? "Updating system automatically..." : "Review the draft below."}`,
            );
            if (isSuperAdmin) {
              commitSchedulesManual(
                result.schedules,
                result.newAgents,
                result.parsedMeta,
              );
            } else {
              setTempSchedules(result.schedules);
              setTempNewAgents(result.newAgents);
              setTempParsedMeta(result.parsedMeta);
            }
          }
        } catch (err: any) {
          const textReader = new FileReader();
          textReader.onload = (eText) => {
            try {
              const text = eText.target?.result as string;
              if (text) {
                const result = parseScheduleCSV(text, agentsList);
                if (result.schedules.length > 0) {
                  setUploadSuccess(
                    `Successfully parsed ${result.schedules.length} shifts. ${isSuperAdmin ? "Updating system automatically..." : "Review the draft below."}`,
                  );
                  if (isSuperAdmin) {
                    commitSchedulesManual(
                      result.schedules,
                      result.newAgents,
                      result.parsedMeta,
                    );
                  } else {
                    setTempSchedules(result.schedules);
                    setTempNewAgents(result.newAgents);
                    setTempParsedMeta(result.parsedMeta);
                  }
                } else {
                  setUploadError(
                    `Failed to parse file: ${err.message || "Unknown error"}`,
                  );
                }
              }
            } catch (fallbackErr: any) {
              setUploadError(
                `Failed to parse file: ${fallbackErr.message || "Unknown error"}`,
              );
            }
          };
          textReader.readAsText(file);
        }
      };
      reader.readAsArrayBuffer(file);
    }
  };

  const commitSchedules = () => {
    commitSchedulesManual(tempSchedules, tempNewAgents, tempParsedMeta);
  };

  const clearTargetSchedules = async () => {
    showConfirm(
      "Clear Schedules",
      "Are you sure you want to completely erase the current schedule roster?",
      "Clear",
      "bg-rose-700 hover:bg-rose-600",
      async () => {
        try {
          setSchedules([]);

          // Also query and delete all docs under the 'schedules' collection in Firestore
          const snap = await getDocs(collection(db, "schedules"));
          const batch = writeBatch(db);
          snap.docs.forEach((doc) => {
            batch.delete(doc.ref);
          });
          await batch.commit();

          toast.success("Schedules cleared.");
        } catch (err: any) {
          console.error("Purging Firestore schedules failed: ", err);
          toast.error("Failed to clear database schedules.");
        }
      },
    );
  };

  const handleScheduleUpload = (file: File) => {
    setRosterUploadSuccess(null);
    setRosterUploadErrors([]);

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const text = e.target?.result as string;
        if (!text) {
          toast.error("File is empty.");
          return;
        }

        const parsed = parseScheduleCSV(text, agentsList);

        if (parsed.schedules.length > 0) {
          setSchedules(parsed.schedules);

          const batch = writeBatch(db);
          parsed.schedules.forEach((s) => {
            batch.set(doc(db, "schedules", s.id), s);
          });
          batch
            .commit()
            .then(() => {
              const affectedAgents = [
                ...new Set(parsed.schedules.map((s) => s.agentName)),
              ];
              affectedAgents.forEach((agentName) => {
                if (agentName) {
                  addSystemNotification(
                    "New Schedule Posted",
                    `Your schedule has been updated by ${currentUser?.name || "a Team Leader"}. Please check your shifts.`,
                    "schedule",
                    String(agentName).trim(),
                  );
                }
              });
              toast.success(
                `Schedule uploaded and ${affectedAgents.length} agent(s) notified.`,
              );
            })
            .catch((e) => console.error("Batch schedules sync error:", e));

          setRosterUploadSuccess(
            `${parsed.schedules.length} shifts successfully imported.`,
          );

          // Dynamically learn any new agent names and add them to the workspace roster so they can be managed
          if (parsed.newAgents && parsed.newAgents.length > 0) {
            const allKnown = new Set(agentsList);
            parsed.newAgents.forEach((a) => {
              if (a && String(a || "").trim()) {
                allKnown.add(String(a || "").trim());
              }
            });
            const updatedList = Array.from(allKnown);
            setAgentsList(updatedList);
            setStorageItem("sched_agents_list", updatedList);
          }
        } else {
          toast.error("No valid shifts could be parsed.");
        }

        if (parsed.errors && parsed.errors.length > 0) {
          setRosterUploadErrors(parsed.errors);
          toast.error(
            `Import completed with ${parsed.errors.length} error(s).`,
          );
        }
      } catch (err: any) {
        toast.error(`Error reading file: ${err?.message || "Unknown error"}`);
        setRosterUploadErrors([`Error: ${err?.message || "Unknown error"}`]);
      }
    };
    reader.readAsText(file);
  };

  const handleClearUploadedSchedules = () => {
    setRosterUploadSuccess(null);
    setRosterUploadErrors([]);
    toast.success("Uploaded schedule cleared. Demo schedule restored.");
  };

  const handleParsedDirectory = (
    result: ReturnType<typeof parseAgentDirectoryCSV>,
  ) => {
    if (result.errors.length > 0)
      toast.error(`Warnings: ${result.errors.slice(0, 3).join(", ")}`);

    if (result.directory.length > 0) {
      setAgentDirectory(result.directory);
      setDirectoryHeaders(result.headers);
      setStorageItem("sched_agent_directory", result.directory);
      setStorageItem("sched_agent_directory_headers", result.headers);

      // Write to Firestore system docs
      setDoc(doc(db, "system", "sched_agent_directory"), {
        data: result.directory,
      }).catch(console.error);
      setDoc(doc(db, "system", "sched_agent_directory_headers"), {
        data: result.headers,
      }).catch(console.error);

      const allKnown = new Set(agentsList);
      result.directory.forEach((a) => allKnown.add(a.agentName));
      const updatedList = Array.from(allKnown);
      setAgentsList(updatedList);
      setStorageItem("sched_agents_list", updatedList);
      setDoc(doc(db, "system", "sched_agents_list"), {
        data: updatedList,
      }).catch(console.error);

      const newMeta = { ...getAgentMeta() };
      let hasMetaUpdate = false;
      const tlHeader = result.headers.find((h) => {
        const lh = h ? String(h).toLowerCase().trim() : " ";
        return (
          lh === "tl" ||
          lh === "team leader" ||
          lh.includes("manager") ||
          lh.includes("supervisor") ||
          lh.includes("lead") ||
          lh === "tl name"
        );
      });
      const roleHeader = result.headers.find((h) => {
        const lh = h ? String(h).toLowerCase().trim() : " ";
        return (
          lh === "role" ||
          lh === "lob" ||
          lh.includes("account") ||
          lh.includes("designation") ||
          lh.includes("job title") ||
          lh.includes("department") ||
          lh.includes("function") ||
          lh.includes("business")
        );
      });

      if (tlHeader || roleHeader) {
        result.directory.forEach((a) => {
          let updated = false;
          if (!newMeta[a.agentName])
            newMeta[a.agentName] = { roleType: "", tlName: "" };
          if (
            tlHeader &&
            a.data[tlHeader] !== undefined &&
            a.data[tlHeader] !== null
          ) {
            const val = String(a.data[tlHeader]).trim();
            if (val) {
              newMeta[a.agentName].tlName = val;
              updated = true;
            }
          }
          if (
            roleHeader &&
            a.data[roleHeader] !== undefined &&
            a.data[roleHeader] !== null
          ) {
            const val = String(a.data[roleHeader]).trim();
            if (val) {
              newMeta[a.agentName].roleType = val;
              updated = true;
            }
          }
          if (updated) hasMetaUpdate = true;
        });
        if (hasMetaUpdate) {
          setStorageItem("sched_agent_meta", newMeta);
          setDoc(doc(db, "system", "sched_agent_meta"), {
            data: newMeta,
          }).catch(console.error);
        }
      }

      // Sync individuals into the users collection as real registeredUsers profiles with smart headers
      result.directory.forEach((a) => {
        const userDocId = a.agentName
          ? String(a.agentName)
              .trim()
              .toLowerCase()
              .replace(/[^a-z0-9]/g, "")
          : "";
        if (userDocId) {
          // Extract email
          const emailVal = (() => {
            for (const k of Object.keys(a.data)) {
              const lk = k
                .toLowerCase()
                .trim()
                .replace(/[\s_-]+/g, "");
              if (
                [
                  "email",
                  "mail",
                  "corpemail",
                  "corporateemail",
                  "emailaddress",
                  "useremail",
                  "workemail",
                ].includes(lk) ||
                ([" email", "mail"].some((term) => lk.includes(term)) &&
                  ![
                    "teamleader",
                    "tl",
                    "lead",
                    "leader",
                    "manager",
                    "supervisor",
                  ].some((term) => lk.includes(term)))
              ) {
                return a.data[k] !== undefined && a.data[k] !== null
                  ? String(a.data[k]).trim()
                  : "";
              }
            }
            return "";
          })();

          // Extract phone
          const phoneVal = (() => {
            for (const k of Object.keys(a.data)) {
              const lk = k
                .toLowerCase()
                .trim()
                .replace(/[\s_-]+/g, "");
              if (
                [
                  "phone",
                  "mobile",
                  "tel",
                  "tele",
                  "contact",
                  "phonenumber",
                ].some(
                  (key) =>
                    lk === key ||
                    lk.startsWith("phone") ||
                    lk.endsWith("phone") ||
                    lk.startsWith("mobile") ||
                    lk.endsWith("mobile") ||
                    lk === "contactnumber" ||
                    (lk.includes("number") &&
                      ![
                        "badge",
                        "serial",
                        "id",
                        "count",
                        "index",
                        "employee",
                        "user",
                        "emp",
                      ].some((t) => lk.includes(t))),
                )
              ) {
                return a.data[k] !== undefined && a.data[k] !== null
                  ? String(a.data[k]).trim()
                  : "";
              }
            }
            return "";
          })();

          // Extract LOB (Line of Business)
          const lobVal = (() => {
            for (const k of Object.keys(a.data)) {
              const lk = k.toLowerCase().trim();
              if (
                lk === "lob" ||
                lk === "line of business" ||
                lk.includes("lob")
              ) {
                return a.data[k] !== undefined && a.data[k] !== null
                  ? String(a.data[k]).trim()
                  : "";
              }
            }
            return "";
          })();

          // Extract LOB Team
          const lobTeamVal = (() => {
            for (const k of Object.keys(a.data)) {
              const lk = k.toLowerCase().trim();
              if (
                lk === "lob team" ||
                lk === "team" ||
                lk === "lob_team" ||
                (lk.includes("team") && lk.includes("lob")) ||
                lk.includes("squad")
              ) {
                return a.data[k] !== undefined && a.data[k] !== null
                  ? String(a.data[k]).trim()
                  : "";
              }
            }
            return "";
          })();

          // Extract Team Leader
          const tlVal = (() => {
            for (const k of Object.keys(a.data)) {
              const lk = k.toLowerCase().trim();
              if (
                lk === "tl" ||
                lk === "team leader" ||
                lk === "tl name" ||
                lk === "manager" ||
                lk === "supervisor" ||
                (lk.includes("team") && lk.includes("leader")) ||
                lk.includes("lead")
              ) {
                return a.data[k] !== undefined && a.data[k] !== null
                  ? String(a.data[k]).trim()
                  : "";
              }
            }
            return "";
          })();

          const userProfile: User = {
            id: userDocId,
            name: a.agentName,
            role: isTLName(a.agentName) ? "tl" : "agent",
            email: emailVal,
            phone: phoneVal, // ← NEW
            lob: lobVal, // ← NEW
            lobTeam: lobTeamVal, // ← NEW
            teamLeader: tlVal, // ← NEW
            directoryData: a.data, // ← NEW: store full CSV row for reference
          };

          setDoc(doc(db, "users", userDocId), userProfile).catch((e) =>
            console.error("User profile sync error:", e),
          );
        }
      });

      toast.success(
        `Successfully loaded and synchronized ${result.directory.length} directory records!`,
      );
    } else {
      throw new Error("No directory entries parsed.");
    }
  };

  const handleDirectoryFile = (file: File) => {
    const isJson = file.name.endsWith(".json");
    if (isJson) {
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const text = event.target?.result as string;
          const parsed = JSON.parse(text);
          if (Array.isArray(parsed) && parsed.length > 0) {
            const headers = Object.keys(parsed[0]);
            const csvText = [
              headers.join(","),
              ...parsed.map((row) =>
                headers
                  .map(
                    (h) => `"${(row[h] || "").toString().replace(/"/g, '""')}"`,
                  )
                  .join(","),
              ),
            ].join("\n");

            const result = parseAgentDirectoryCSV(csvText);
            handleParsedDirectory(result);
          } else {
            toast.error("Invalid JSON structure for directory");
          }
        } catch (e: any) {
          toast.error(`JSON Parse Error: ${e.message}`);
        }
      };
      reader.readAsText(file);
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = new Uint8Array(event.target?.result as ArrayBuffer);
        const workbook = XLSX.read(data, { type: "array" });
        if (!workbook.SheetNames || workbook.SheetNames.length === 0)
          throw new Error("No worksheets found in this file.");
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const csvText = XLSX.utils.sheet_to_csv(worksheet);
        if (!csvText || !String(csvText || "").trim())
          throw new Error("Could not extract sheet content.");

        const result = parseAgentDirectoryCSV(csvText);
        handleParsedDirectory(result);
      } catch (err: any) {
        const textReader = new FileReader();
        textReader.onload = (eText) => {
          try {
            const text = eText.target?.result as string;
            if (text) {
              const result = parseAgentDirectoryCSV(text);
              handleParsedDirectory(result);
            }
          } catch (fallbackErr: any) {
            toast.error(`Could not parse text: ${fallbackErr.message}`);
          }
        };
        textReader.readAsText(file);
      }
    };
    reader.readAsArrayBuffer(file);
  };

  const handleManualRosterSubmit = (e: FormEvent) => {
    e.preventDefault();
    if (!manualRosterAgent) {
      toast.error("Please select or specify an agent name.");
      return;
    }
    if (!manualRosterDate) {
      toast.error("Please specify a roster shift date.");
      return;
    }
    if (!manualRosterShift) {
      toast.error("Please select an active shift assignment.");
      return;
    }

    const newShift: ScheduledShift = {
      id: `sch_man_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      agentName: manualRosterAgent,
      date: manualRosterDate,
      shiftLabel: manualRosterShift,
      shiftNotes: String(manualRosterNotes || "").trim() || undefined,
    };

    commitSchedulesManual([newShift], [], {});
    setManualRosterNotes("");
    toast.success(
      `Individual shift for ${manualRosterAgent} successfully submitted and synced!`,
    );
  };

  // Agent Time Clock & Activity Helpers
  const getActiveTimeLog = (agentName: string): TimeLog | undefined => {
    return timeLogs.find(
      (log) =>
        log.agentName?.toLowerCase() === agentName?.toLowerCase() &&
        !["clocked_out", "day_off", "casual", "annual", "no_show"].includes(
          log.status,
        ),
    );
  };

  const getTodayLog = (agentName: string) => {
    const todayStr = getLocalISOString();
    return timeLogs.find(
      (log) =>
        log.agentName?.toLowerCase() === agentName?.toLowerCase() &&
        log.date === todayStr,
    );
  };

  const getAgentTodayStats = (agentName: string) => {
    const todayStr = getLocalISOString();
    const myLogsToday = timeLogs.filter(
      (l) =>
        l.agentName?.toLowerCase() === agentName?.toLowerCase() &&
        l.date === todayStr,
    );

    let totalClockInStr: string | null = null;
    let totalClockOutStr: string | null = null;
    let totalBreakMins = 0;
    let totalLunchMins = 0;
    let totalRestroomMins = 0;
    let restroomCount = 0;
    let totalMeetingMins = 0;
    let totalOneOnOneMins = 0;
    let totalPersonalMins = 0;

    if (myLogsToday.length > 0) {
      // Sort to get first clock in and last clock out
      const sorted = [...myLogsToday].sort(
        (a, b) =>
          new Date(a.clockIn || 0).getTime() -
          new Date(b.clockIn || 0).getTime(),
      );
      totalClockInStr = sorted[0].clockIn || null;
      const lastWithOut = [...myLogsToday].reverse().find((l) => l.clockOut);
      totalClockOutStr = lastWithOut ? lastWithOut.clockOut || null : null;

      myLogsToday.forEach((log) => {
        log.activities.forEach((act) => {
          let duration = 0;
          if (act.durationMinutes !== undefined) {
            duration = act.durationMinutes;
          } else if (!act.endTime) {
            // running!
            const diffMs =
              currentTime.getTime() - new Date(act.startTime).getTime();
            duration = diffMs / 1000 / 60;
          }

          if (act.type === "break") totalBreakMins += duration;
          else if (act.type === "lunch") totalLunchMins += duration;
          else if (act.type === "restroom") totalRestroomMins += duration;
          else if (act.type === "meeting") totalMeetingMins += duration;
          else if (act.type === "one_on_one") totalOneOnOneMins += duration;
          else if (act.type === "personal") totalPersonalMins += duration;
        });

        restroomCount += log.activities.filter(
          (a) => a.type === "restroom",
        ).length;
      });
    }

    return {
      clockIn: totalClockInStr,
      clockOut: totalClockOutStr,
      breakMins: parseFloat(totalBreakMins.toFixed(2)),
      lunchMins: parseFloat(totalLunchMins.toFixed(2)),
      restroomMins: parseFloat(totalRestroomMins.toFixed(2)),
      restroomCount,
      meetingMins: parseFloat(totalMeetingMins.toFixed(2)),
      oneOnOneMins: parseFloat(totalOneOnOneMins.toFixed(2)),
      personalMins: parseFloat(totalPersonalMins.toFixed(2)),
    };
  };

  const getActiveActivityElapsed = (agentName: string) => {
    const active = getActiveTimeLog(agentName);
    if (
      !active ||
      active.status === "working" ||
      active.status === "clocked_out"
    )
      return null;

    const currentAct = active.activities.find(
      (a) => !a.endTime && a.type === active.status,
    );
    if (!currentAct) return null;

    const diffMs =
      currentTime.getTime() - new Date(currentAct.startTime).getTime();
    const durationMins = diffMs / 1000 / 60;

    let limit = 0;
    if (active.status === "break") limit = 15;
    else if (active.status === "lunch") limit = 30;
    else if (active.status === "restroom") limit = 10;
    else if (active.status === "meeting") limit = 60;
    else if (active.status === "one_on_one") limit = 30;
    else if (active.status === "personal") limit = 15;

    return {
      id: currentAct.id,
      type: active.status as
        | "break"
        | "lunch"
        | "restroom"
        | "meeting"
        | "one_on_one"
        | "personal",
      limit,
      duration: durationMins,
      exceeded: limit > 0 && durationMins > limit,
      exceededBy: limit > 0 ? Math.max(0, durationMins - limit) : 0,
    };
  };

  const handleClockIn = () => {
    if (!currentUser) return;
    const name = currentUser.name;
    const todayStr = getLocalISOString();

    const active = getActiveTimeLog(name);
    if (active) {
      toast.error("You are already clocked in!");
      return;
    }

    const newLog: TimeLog = {
      id: `clock_${Date.now()}`,
      agentName: name,
      date: todayStr,
      clockIn: new Date().toISOString(),
      activities: [],
      status: "working",
    };

    const updated = [newLog, ...timeLogs];
    setTimeLogs(updated);
    setStorageItem("sched_time_logs", updated);

    // Sync to Firestore
    setDoc(doc(db, "timelogs", newLog.id), newLog).catch((e) =>
      console.error("Clock In Error:", e),
    );
  };

  const handleStartActivity = (
    type:
      | "break"
      | "lunch"
      | "restroom"
      | "meeting"
      | "one_on_one"
      | "personal",
  ) => {
    if (!currentUser) return;
    const name = currentUser.name;
    const active = getActiveTimeLog(name);
    if (!active) {
      toast.error("You must clock in first before starting any AUX session!");
      return;
    }

    const previousStatus = active.status;
    if (previousStatus === type) {
      toast.info(`You are already on: ${type}`);
      return;
    }

    const nowStr = new Date().toISOString();
    const newAct: ActivityRecord = {
      id: `act_${Date.now()}`,
      type,
      startTime: nowStr,
    };

    const friendlyNameMap: Record<string, string> = {
      break: "Break",
      lunch: "Lunch",
      restroom: "Restroom Break",
      meeting: "Team Meeting",
      one_on_one: "1:1 Session",
      personal: "Personal Break",
      working: "Active Work",
    };

    const updated = timeLogs.map((log) => {
      if (log.id === active.id) {
        // If they were on a different AUX, terminate the running one
        let updatedActivities = [...log.activities];
        if (previousStatus !== "working") {
          updatedActivities = updatedActivities.map((act) => {
            if (!act.endTime && act.type === previousStatus) {
              const diffMs =
                new Date(nowStr).getTime() - new Date(act.startTime).getTime();
              let diffMins = parseFloat((diffMs / 1000 / 60).toFixed(2));
              if (isNaN(diffMins)) diffMins = 0;
              return {
                ...act,
                endTime: nowStr,
                durationMinutes: diffMins,
              };
            }
            return act;
          });
        }

        const updatedLog = {
          ...log,
          status: type,
          activities: [...updatedActivities, newAct],
        };
        // Sync to Firestore
        setDoc(doc(db, "timelogs", log.id), updatedLog).catch((e) =>
          console.error("AUX Start Error:", e),
        );
        return updatedLog;
      }
      return log;
    });

    setTimeLogs(updated);
    setStorageItem("sched_time_logs", updated);

    // Let TL know about this AUX switch!
    const fromStatusLabel = friendlyNameMap[previousStatus] || previousStatus;
    const toStatusLabel = friendlyNameMap[type] || type;
    addSystemNotification(
      `Status Switch: ${formatAgentName(name)}`,
      `${formatAgentName(name)} switched AUX status from **${fromStatusLabel}** to **${toStatusLabel}**.`,
      "compliance",
      "tl",
    );
    toast.success(`Switched from ${fromStatusLabel} to ${toStatusLabel}!`);
  };

  const handleEndActivity = () => {
    if (!currentUser) return;
    const name = currentUser.name;
    const active = getActiveTimeLog(name);
    if (
      !active ||
      active.status === "working" ||
      active.status === "clocked_out"
    ) {
      toast.error("No active activity to end.");
      return;
    }

    const currentType = active.status;
    const endTimeStr = new Date().toISOString();

    const updated = timeLogs.map((log) => {
      if (log.id === active.id) {
        const updatedActivities = log.activities.map((act) => {
          if (!act.endTime && act.type === currentType) {
            const diffMs =
              new Date(endTimeStr).getTime() -
              new Date(act.startTime).getTime();
            let diffMins = parseFloat((diffMs / 1000 / 60).toFixed(2));
            if (isNaN(diffMins)) diffMins = 0;
            return {
              ...act,
              endTime: endTimeStr,
              durationMinutes: diffMins,
            };
          }
          return act;
        });

        const updatedLog = {
          ...log,
          status: "working" as const,
          activities: updatedActivities,
        };
        // Sync to Firestore
        setDoc(doc(db, "timelogs", log.id), updatedLog).catch((e) =>
          console.error("AUX End Error:", e),
        );
        return updatedLog;
      }
      return log;
    });

    setTimeLogs(updated);
    setStorageItem("sched_time_logs", updated);

    const friendlyNameMap: Record<string, string> = {
      break: "Break",
      lunch: "Lunch",
      restroom: "Restroom Break",
      meeting: "Team Meeting",
      one_on_one: "1:1 Session",
      personal: "Personal Break",
    };
    const actLabel = friendlyNameMap[currentType] || currentType;
    addSystemNotification(
      `Agent Back Online: ${formatAgentName(name)}`,
      `${formatAgentName(name)} completed their ${actLabel} session and is now **Active Work**.`,
      "compliance",
      "tl",
    );
    toast.success(`Resumed standard work from ${actLabel}!`);
  };

  const handleClockOut = () => {
    if (!currentUser) return;
    const name = currentUser.name;
    const active = getActiveTimeLog(name);
    if (!active) {
      toast.error("You are not currently clocked in!");
      return;
    }

    showConfirm(
      "Clock Out",
      "Are you sure you want to clock out of your shift?",
      "Clock Out",
      "bg-emerald-600 hover:bg-emerald-500",
      () => {
        const endTimeStr = new Date().toISOString();

        const updated = timeLogs.map((log) => {
          if (log.id === active.id) {
            const updatedActivities = log.activities.map((act) => {
              if (!act.endTime) {
                const diffMs =
                  new Date(endTimeStr).getTime() -
                  new Date(act.startTime).getTime();
                let diffMins = parseFloat((diffMs / 1000 / 60).toFixed(2));
                if (isNaN(diffMins)) diffMins = 0;
                return {
                  ...act,
                  endTime: endTimeStr,
                  durationMinutes: diffMins,
                };
              }
              return act;
            });

            return {
              ...log,
              clockOut: endTimeStr,
              status: "clocked_out" as const,
              activities: updatedActivities,
            };
          }
          return log;
        });

        setTimeLogs(updated);
        setStorageItem("sched_time_logs", updated);
      },
    );
  };

  const handleTLOverrideAgentStatus = (
    agentName: string,
    newStatus:
      | "working"
      | "break"
      | "lunch"
      | "restroom"
      | "clocked_out"
      | "day_off"
      | "casual"
      | "annual"
      | "no_show"
      | "meeting"
      | "one_on_one"
      | "personal",
  ) => {
    const todayStr = getLocalISOString();
    const active = getActiveTimeLog(agentName);
    const endTimeStr = new Date().toISOString();

    let updated = [...timeLogs];

    if (active) {
      updated = updated.map((log) => {
        if (log.id === active.id) {
          // If moving to an inactive state, end the shift
          if (
            ["clocked_out", "day_off", "casual", "annual", "no_show"].includes(
              newStatus,
            )
          ) {
            const updatedActivities = log.activities.map((act) => {
              if (!act.endTime) {
                const diffMs =
                  new Date(endTimeStr).getTime() -
                  new Date(act.startTime).getTime();
                return {
                  ...act,
                  endTime: endTimeStr,
                  durationMinutes: parseFloat((diffMs / 1000 / 60).toFixed(2)),
                };
              }
              return act;
            });
            return {
              ...log,
              clockOut: endTimeStr,
              status: newStatus as any,
              activities: updatedActivities,
            };
          } else {
            // If changing to working/break/lunch/restroom
            let updatedActivities = log.activities.map((act) => {
              if (!act.endTime) {
                const diffMs =
                  new Date(endTimeStr).getTime() -
                  new Date(act.startTime).getTime();
                return {
                  ...act,
                  endTime: endTimeStr,
                  durationMinutes: parseFloat((diffMs / 1000 / 60).toFixed(2)),
                };
              }
              return act;
            });

            if (newStatus !== "working") {
              updatedActivities.push({
                id: `act_${Date.now()}`,
                type: newStatus as any,
                startTime: endTimeStr,
              });
            }

            return {
              ...log,
              status: newStatus as any,
              activities: updatedActivities,
            };
          }
        }
        return log;
      });
    } else {
      // If no active log for today, we either clock them in or mark them absent
      const newLog: TimeLog = {
        id: `override_${Date.now()}`,
        agentName: agentName,
        date: todayStr,
        clockIn: ["working", "break", "lunch", "restroom"].includes(newStatus)
          ? endTimeStr
          : undefined,
        activities: ["break", "lunch", "restroom"].includes(newStatus)
          ? [
              {
                id: `act_${Date.now()}`,
                type: newStatus as any,
                startTime: endTimeStr,
              },
            ]
          : [],
        status: newStatus as any,
      };
      // remove any empty log for today, just add this fresh one
      updated = [newLog, ...updated];
    }

    setTimeLogs(updated);
    setStorageItem("sched_time_logs", updated);
  };

  // Inquiry Submission and Processing System
  const handleAddPhotoUrl = () => {
    if (!String(tempPhotoUrlInput || "").trim()) return;
    setInquiryPhotos([
      ...inquiryPhotos,
      String(tempPhotoUrlInput || "").trim(),
    ]);
    setTempPhotoUrlInput("");
  };

  const handleRemovePhoto = (index: number) => {
    setInquiryPhotos(inquiryPhotos.filter((_, i) => i !== index));
  };

  const handleAddLink = () => {
    if (!String(tempLinkInput || "").trim()) return;
    let url = String(tempLinkInput || "").trim();
    if (!/^https?:\/\//i.test(url)) {
      url = "https://" + url;
    }
    setInquiryLinks([...inquiryLinks, url]);
    setTempLinkInput("");
  };

  const handleRemoveLink = (index: number) => {
    setInquiryLinks(inquiryLinks.filter((_, i) => i !== index));
  };

  const handlePhotoFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    Array.from(files).forEach((file: any) => {
      const reader = new FileReader();
      reader.onload = (event) => {
        if (event.target?.result) {
          setInquiryPhotos((prev) => [...prev, event.target!.result as string]);
        }
      };
      reader.readAsDataURL(file);
    });
  };

  const handleSubmitInquiry = async (e: FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;
    if (isFormSubmitting) return;

    if (!inquiryClinicName) {
      toast.error("Please select a Clinic Name! This is a mandatory field.");
      return;
    }

    if (!inquiryPlatform) {
      toast.error("Please select a Platform! This is a mandatory field.");
      return;
    }

    if (!String(inquiryPatientName || "").trim()) {
      toast.error(
        "Please enter the Patient Name! This is now a mandatory field.",
      );
      return;
    }

    if (!String(inquiryPhoneNumber || "").trim()) {
      toast.error(
        "Please enter the Patient Phone Number! This is now a mandatory field.",
      );
      return;
    }

    if (
      inquiryCustomerType === "old" &&
      !String(inquiryFileNumber || "").trim()
    ) {
      toast.error(
        "For Old Customers, typing the Patient File / ID Number is required!",
      );
      return;
    }

    if (!String(inquiryText || "").trim()) {
      toast.error("Please enter your inquiry text!");
      return;
    }

    setIsFormSubmitting(true);
    try {
      const createdAt = new Date().toISOString();
      let safeId = "inq_";
      if (
        typeof crypto !== "undefined" &&
        typeof crypto.randomUUID === "function"
      ) {
        safeId += `${Date.now()}_${crypto.randomUUID().slice(0, 8)}`;
      } else {
        safeId += `${Date.now()}_${Math.random().toString(36).substring(2, 10)}`;
      }
      const inquiryId = safeId;

      const processedAttachments = await processAttachments(
        inquiryAttachments,
        "inquiry",
        inquiryId,
        "root",
      );

      const allPhotos = [
        ...(inquiryPhotos || []),
        ...(activeScreenshot ? [activeScreenshot] : []),
      ];

      const newInquiry: Inquiry = {
        id: inquiryId,
        caseRef: formatCaseRef(inquiryId, "inquiry", createdAt),
        agentName: currentUser.name,
        clinicName: inquiryClinicName,
        patientName: String(inquiryPatientName || "").trim(),
        fileNumber:
          inquiryCustomerType === "old"
            ? String(inquiryFileNumber || "").trim()
            : undefined,
        fileId: String(inquiryFileId || "").trim(),
        phoneNumber: String(inquiryPhoneNumber || "").trim(),
        customerType: inquiryCustomerType,
        platform: inquiryPlatform,
        text: String(inquiryText || "").trim(),
        photos: allPhotos,
        screenshot: activeScreenshot || null, // keep for backward compat
        attachments: processedAttachments,
        links: inquiryLinks,
        createdAt,
        status: "submitted",
        seenByAgent: false,
      };

      setInquiries((prev) => {
        const updated = [newInquiry, ...prev];
        setStorageItem("sched_inquiries", updated);
        return updated;
      });

      // Sync to Firestore
      await setDoc(doc(db, "inquiries", newInquiry.id), newInquiry);

      // Reset fields
      setInquiryText("");
      setInquiryClinicName("");
      setInquiryPhoneNumber("");
      setInquiryPatientName("");
      setInquiryFileNumber("");
      setInquiryFileId("");
      setInquiryPlatform("");
      setInquiryCustomerType("new");
      setInquiryPhotos([]);
      setInquiryAttachments([]);
      setInquiryLinks([]);
      setTempLinkInput("");
      setTempPhotoUrlInput("");

      handleMentionsInText(
        String(inquiryText || "").trim(),
        "Agent Inquiry Description",
        currentUser.name,
      );
      addSystemNotification(
        "New Inquiry Submitted",
        `${currentUser.name} has submitted a new inquiry for clinic: ${inquiryClinicName}.`,
        "general",
        "tl",
        undefined,
        "inquiry",
        newInquiry.id,
      );

      setSubmissionConfirmation({
        title: "Inquiry Logged Successfully! ",
        message: `Your inquiry has been successfully transmitted to the database. The Team Leaders have been notified and will reply shortly.`,
        type: "inquiry",
        referenceId: newInquiry.id,
      });
      window.scrollTo({ top: 0, behavior: "smooth" });
    } catch (err) {
      console.error(err);
      toast.error("An error occurred while submitting. Please try again.");
    } finally {
      setIsFormSubmitting(false);
    }
  };

  const handleTLViewInquiry = (inquiryId: string) => {
    if (!currentUser || currentUser.role !== "tl") return;

    let targetInq: any = null;

    const inqObj = inquiries.find((i) => i.id === inquiryId);
    if (!inqObj || inqObj.viewingStatus === "tl_viewing") return;

    const updated = inquiries.map((inq) => {
      if (inq.id === inquiryId) {
        targetInq = inq;
        const updatedInq = {
          ...inq,
          viewingStatus: "tl_viewing" as const,
          viewingBy: currentUser.name,
          viewingAt: new Date().toISOString(),
        };
        // Sync to Firestore
        setDoc(doc(db, "inquiries", inq.id), updatedInq).catch((e) =>
          console.error("Inquiry View Update Error:", e),
        );
        return updatedInq;
      }
      return inq;
    });

    setInquiries(updated);
    setStorageItem("sched_inquiries", updated);

    if (targetInq) {
      addSystemNotification(
        "Team Leader Reviewing Your Inquiry",
        `"${currentUser.name} is now reviewing your inquiry for clinic ${targetInq.clinicName}."`,
        "inquiry",
        targetInq.agentName,
        undefined,
        "inquiry",
        targetInq.id,
      );
    }
  };

  const generateClinicTemplate = (inq: Inquiry): string => {
    const ref = inq.caseRef || `INQ-${inq.id.substring(0, 8).toUpperCase()}`;
    const pName = inq.patientName || "N/A";
    const fId = inq.fileId || inq.fileNumber || "N/A";
    const pId = inq.patientId || "N/A";
    const pPhone = inq.phoneNumber
      ? formatPhoneForCopy(inq.phoneNumber)
      : "N/A";

    return [
      `📋 *CLINICAL INQUIRY TEMPLATE*`,
      `-----------------------------------`,
      `🆔 *Reference:* ${ref}`,
      `🏥 *Clinic:* ${getClinicLabel(inq.clinicName)}`,
      `👤 *Patient:* ${pName}`,
      `📁 *File ID:* ${fId}`,
      `🔑 *Patient ID:* ${pId}`,
      `📞 *Phone:* ${pPhone}`,
      `💬 *Inquiry Details:*`,
      `${inq.text || "—"}`,
      `-----------------------------------`,
      `🧑‍💼 *Agent:* ${inq.agentName}`,
      `📅 *Date:* ${inq.createdAt ? new Date(inq.createdAt).toLocaleString() : "N/A"}`,
    ].join("\n");
  };

  const handleSetInquirySent = async (inquiryId: string, skipModal = false) => {
    if (!currentUser || currentUser.role !== "tl") return;

    const inqObj = inquiries.find((i) => i.id === inquiryId);
    if (!inqObj) return;

    if (!skipModal) {
      setTemplateInquiryId(inquiryId);
      setShowClinicTemplateModal(true);
      return;
    }

    let sentInquiry: any = null;

    // Generate template and copy to clipboard
    const templateText = generateClinicTemplate(inqObj);
    try {
      await copyToClipboard(
        templateText,
        "Standard clinic template copied to clipboard!",
      );
    } catch (e) {
      console.error("Fails to copy standard template:", e);
    }

    const updated = inquiries.map((inq) => {
      if (inq.id === inquiryId) {
        sentInquiry = inq;
        const updatedInq = {
          ...inq,
          status: "sent" as const,
          sentBy: currentUser.name,
          sentAt: new Date().toISOString(),
          seenByAgent: false,
        };
        // Sync to Firestore
        setDoc(doc(db, "inquiries", inq.id), updatedInq).catch((e) =>
          console.error("Inquiry Update Error:", e),
        );
        return updatedInq;
      }
      return inq;
    });

    setInquiries(updated);
    setStorageItem("sched_inquiries", updated);
    setShowClinicTemplateModal(false);
    setTemplateInquiryId(null);

    if (sentInquiry) {
      addSystemNotification(
        "Inquiry Forwarded to Partner",
        `Your inquiry for clinic ${sentInquiry.clinicName} has been forwarded to the partner by ${currentUser.name}.`,
        "inquiry",
        sentInquiry.agentName,
        undefined,
        "inquiry",
        sentInquiry.id,
      );
    }
  };

  const handleMarkInquiryRead = async (inquiryId: string) => {
    if (!currentUser) return;
    const inq = inquiries.find((i) => i.id === inquiryId);
    if (!inq) return;
    const now = new Date().toISOString();
    const newStatus = inq.status === "submitted" ? "tl_reviewing" : inq.status;

    const updated = inquiries.map((i) =>
      i.id === inquiryId
        ? {
            ...i,
            status: newStatus as any,
            readBy: currentUser.name,
            readAt: now,
          }
        : i,
    );
    setInquiries(updated);
    setStorageItem("sched_inquiries", updated);
    await updateDoc(doc(db, "inquiries", inquiryId), {
      status: newStatus,
      readBy: currentUser.name,
      readAt: now,
    }).catch((e) => console.error("Mark read error:", e));
  };

  const handleMarkSentToClinic = async (inquiryId: string) => {
    if (!currentUser) return;
    const inq = inquiries.find((i) => i.id === inquiryId);
    if (!inq) return;

    const now = new Date().toISOString();
    const newCount = (inq.sentToClinicCount || 0) + 1;
    const inqForTemplate = {
      ...inq,
      sentToClinicCount: inq.sentToClinicCount || 0,
    };

    // Build rich (HTML + plain text) clipboard content
    const plainText = buildClinicInquiryTextTemplate(inqForTemplate);
    const htmlContent = buildClinicInquiryHtmlTemplate(inqForTemplate);

    const copied = await copyToClipboard(
      plainText,
      `Inquiry copied with ${(inq.attachments?.length || 0) + (inq.photos?.length || 0)} attachment(s)! Paste into the clinic's WhatsApp group.`,
      htmlContent,
    );
    if (!copied) return;

    const updated = inquiries.map((i) =>
      i.id === inquiryId
        ? {
            ...i,
            status: "sent_to_clinic" as const,
            sentBy: currentUser.name,
            sentAt: now,
            sentToClinicCount: newCount,
          }
        : i,
    );
    setInquiries(updated);
    setStorageItem("sched_inquiries", updated);
    await updateDoc(doc(db, "inquiries", inquiryId), {
      status: "sent_to_clinic",
      sentBy: currentUser.name,
      sentAt: now,
      sentToClinicCount: newCount,
    }).catch((e) => console.error("Mark sent error:", e));

    addSystemNotification(
      "Inquiry Sent to Clinic",
      `${currentUser.name} sent your inquiry to ${getClinicLabel(inq.clinicName)} — awaiting their response.`,
      "general",
      inq.agentName,
      undefined,
      "inquiry",
      inquiryId,
    );
  };

  const handleCloseInquiry = async (inquiryId: string) => {
    if (!currentUser) return;
    const now = new Date().toISOString();
    const inq = inquiries.find((i) => i.id === inquiryId);
    if (!inq) return;

    const updated = inquiries.map((i) =>
      i.id === inquiryId
        ? {
            ...i,
            status: "closed" as const,
            closedBy: currentUser.name,
            closedAt: now,
          }
        : i,
    );
    setInquiries(updated);
    setStorageItem("sched_inquiries", updated);
    await updateDoc(doc(db, "inquiries", inquiryId), {
      status: "closed",
      closedBy: currentUser.name,
      closedAt: now,
    }).catch((e) => console.error("Close inquiry error:", e));

    let timerMessage = "";
    if (inq.answeredAt) {
      const msDiff =
        new Date(now).getTime() - new Date(inq.answeredAt).getTime();
      const minsTotal = Math.floor(msDiff / 60000);
      const hours = Math.floor(minsTotal / 60);
      const mins = minsTotal % 60;
      if (hours > 0) {
        timerMessage = ` (Time in answered status before manually closing: ${hours}h ${mins}m)`;
      } else {
        timerMessage = ` (Time in answered status before manually closing: ${mins}m)`;
      }
    } else {
      const msDiff =
        new Date(now).getTime() - new Date(inq.createdAt).getTime();
      const minsTotal = Math.floor(msDiff / 60000);
      const hours = Math.floor(minsTotal / 60);
      const mins = minsTotal % 60;
      if (hours > 0) {
        timerMessage = ` (Total duration since creation: ${hours}h ${mins}m)`;
      } else {
        timerMessage = ` (Total duration since creation: ${mins}m)`;
      }
    }

    const refCode =
      inq.caseRef || `INQ-${inq.id.replace("inq_", "").toUpperCase()}`;
    addSystemNotification(
      "Inquiry Closed Manually",
      `Inquiry ${refCode} for ${getClinicLabel(inq.clinicName)} has been closed manually by ${currentUser.name}${timerMessage}.`,
      "general",
      "all",
      undefined,
      "inquiry",
      inquiryId,
    );
  };

  const handleSetInquiryAnswered = async (inquiryId: string) => {
    if (!currentUser) return;
    if (isSubmittingAnswer) return;

    const answerText = String(currentAnswerText || "").trim();
    if (!answerText) {
      toast.error("Reply text cannot be empty.");
      return;
    }

    if (answerText.length > 500) {
      toast.error("Reply details cannot exceed 500 characters.");
      return;
    }

    setIsSubmittingAnswer(true);

    try {
      const processedAttachments = await processAttachments(
        currentAnswerAttachments,
        "inquiry",
        inquiryId,
        "reply",
      );

      let targetAgentName = "";
      let clinicName = "";
      let updatedInqObject: Inquiry | null = null;
      let finalAnswerString = answerText || "See structured reply timeline...";

      const isAgent = currentUser.role === "agent";
      const newStatus = isAgent
        ? ("tl_reviewing" as const)
        : ("answered" as const);

      const updated = inquiries.map((inq) => {
        if (inq.id === inquiryId) {
          targetAgentName = inq.agentName;
          clinicName = inq.clinicName;

          const newReply = {
            id: `reply_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            authorId: currentUser.id,
            senderName: currentUser.name,
            authorRole: currentUser.role,
            text: answerText,
            attachments:
              processedAttachments.length > 0
                ? processedAttachments
                : undefined,
            links:
              currentAnswerLinks.length > 0 ? currentAnswerLinks : undefined,
            createdAt: new Date().toISOString(),
          };

          const updatedInq: Inquiry = {
            ...inq,
            status: newStatus,
            answer: isAgent
              ? inq.answer || finalAnswerString
              : finalAnswerString, // keep for backward compatibility
            answeredBy: isAgent ? inq.answeredBy || null : currentUser.name,
            answeredAt: isAgent
              ? inq.answeredAt || null
              : new Date().toISOString(),
            seenByAgent: isAgent ? true : false,
            replies: [...(inq.replies || []), newReply],
          };
          updatedInqObject = updatedInq;
          return updatedInq;
        }
        return inq;
      });

      if (!updatedInqObject) {
        setIsSubmittingAnswer(false);
        return;
      }

      await setDoc(doc(db, "inquiries", inquiryId), updatedInqObject);

      setInquiries(updated);
      setStorageItem("sched_inquiries", updated);

      if (isAgent) {
        addSystemNotification(
          "Inquiry Replied by Agent",
          `Agent ${currentUser.name} has replied to the inquiry regarding clinic "${clinicName}".`,
          "inquiry",
          "tl",
          undefined,
          "inquiry",
          inquiryId,
        );
      } else {
        if (targetAgentName) {
          addSystemNotification(
            "Inquiry Answered by TL",
            `Your inquiry regarding clinic "${clinicName}" has been answered by ${currentUser.name}.`,
            "inquiry",
            targetAgentName,
            undefined,
            "inquiry",
            inquiryId,
          );
        }
      }
      handleMentionsInText(answerText, "Inquiry Response", currentUser.name);

      setAnsweringInquiryId(null);
      setCurrentAnswerText("");
      setCurrentAnswerAttachments([]);
      setCurrentAnswerLinks([]);
      toast.success(
        isAgent
          ? "Reply sent successfully! TL will receive a live notification."
          : "Answer response committed successfully! Agent will receive a live notification.",
      );
    } catch (e: any) {
      console.error("Inquiry Answer Error:", e);
      toast.error(`Database Error: Failed to save reply. ${e.message}`);
    } finally {
      setIsSubmittingAnswer(false);
    }
  };

  const handleReassignInquiry = (inquiryId: string, newAgentName: string) => {
    if (!currentUser || currentUser.role !== "tl") return;
    if (!newAgentName) return;

    const updated = inquiries.map((inq) => {
      if (inq.id === inquiryId) {
        const updatedInq = {
          ...inq,
          agentName: newAgentName,
          seenByAgent: false,
        };
        // Sync to Firestore
        setDoc(doc(db, "inquiries", inq.id), updatedInq).catch((e) =>
          console.error("Inquiry Reassign Error:", e),
        );
        return updatedInq;
      }
      return inq;
    });

    setInquiries(updated);
    setStorageItem("sched_inquiries", updated);
  };

  const handleUpdateContactedStatus = (
    inquiryId: string,
    status: "not_contacted" | "contacted" | "attempted",
  ) => {
    const updated = inquiries.map((inq) => {
      if (inq.id === inquiryId) {
        const updatedInq = {
          ...inq,
          customerContacted: status,
        };
        // Sync to Firestore
        setDoc(doc(db, "inquiries", inq.id), updatedInq).catch((e) =>
          console.error("Inquiry Contacted Status Error:", e),
        );
        return updatedInq;
      }
      return inq;
    });
    setInquiries(updated);
    setStorageItem("sched_inquiries", updated);
  };

  const handleMarkInquirySeen = (inquiryId: string) => {
    const updated = inquiries.map((inq) => {
      if (inq.id === inquiryId) {
        const updatedInq = { ...inq, seenByAgent: true };
        // Sync to Firestore
        setDoc(doc(db, "inquiries", inq.id), updatedInq).catch((e) =>
          console.error("Inquiry Mark Seen Error:", e),
        );
        return updatedInq;
      }
      return inq;
    });
    setInquiries(updated);
    setStorageItem("sched_inquiries", updated);
  };

  const handleDeleteInquiry = (inquiryId: string) => {
    showConfirm(
      "Delete Inquiry",
      "Are you sure you want to delete this inquiry record?",
      "Delete",
      "bg-rose-700 hover:bg-rose-600",
      () => {
        const updated = inquiries.filter((inq) => inq.id !== inquiryId);
        setInquiries(updated);
        setStorageItem("sched_inquiries", updated);
        // Sync to Firestore
        deleteDoc(doc(db, "inquiries", inquiryId)).catch((e) =>
          console.error("Inquiry Delete Error:", e),
        );
      },
    );
  };

  const handleSubmitTabbyTamara = async (e: FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;
    if (isFormSubmitting) return;

    if (
      !ttPatientName ||
      !ttPriceWithoutTax ||
      !ttPhoneNumber ||
      !ttClinicName
    ) {
      toast.error(
        "Please fill out all mandatory fields (Patient Name, Price, Phone Number, Clinic Name).",
      );
      return;
    }

    if (!ttIsOldCustomer && !ttIdNumber) {
      toast.error(
        "Since the customer is not an old customer, please enter their ID Number.",
      );
      return;
    }

    setIsFormSubmitting(true);
    try {
      const pricing = calculateTabbyTamaraPrice(ttPriceWithoutTax);
      if (!pricing.valid) {
        toast.error("Enter a valid price greater than zero.");
        setIsFormSubmitting(false);
        return;
      }

      const autoNote = `[5% added to price. Final: ${pricing.finalPriceFormatted}]`;
      const finalNotes = ttNotes
        ? `${autoNote}

${ttNotes}`
        : autoNote;

      const userLob = getAgentLOB(currentUser.name);
      const isCc = userLob === "Call Center";
      const channelLabel = isCc ? "call_center" : "chat";

      const createdAt = new Date().toISOString();
      let safeId = "tt_";
      if (
        typeof crypto !== "undefined" &&
        typeof crypto.randomUUID === "function"
      ) {
        safeId += `${Date.now()}_${crypto.randomUUID().slice(0, 8)}`;
      } else {
        safeId += `${Date.now()}_${Math.random().toString(36).substring(2, 10)}`;
      }
      const id = safeId;

      const newRequest: any = {
        id,
        caseRef: formatCaseRef(id, "tt_request", createdAt),
        agentName: currentUser.name,
        patientName: ttPatientName,
        fileNumber: ttFileNumber,
        isOldCustomer: ttIsOldCustomer,
        idNumber: !ttIsOldCustomer ? ttIdNumber : null,
        priceWithoutTax: ttPriceWithoutTax,
        feeRate: 0.05,
        feeAmount: pricing.feeAmount,
        finalPriceWithFee: pricing.finalPrice,
        currency: "AED",
        phoneNumber: ttPhoneNumber,
        notes: finalNotes,
        createdAt,
        status: "not_confirmed",
        customerContacted: "not_contacted",

        platform: ttPlatform,
        clinicName: ttClinicName,
        paymentScreenshot: activeScreenshot || null,
        photos: activePhotos,
        links: activeLinks,

        // New workflow fields
        workflowStatus: "submitted",
        sourceChannel: channelLabel,
        submittedById: currentUser.id || "",
        submittedByName: currentUser.name,
        updatedAt: new Date().toISOString(),
        replies: [],
        clientIdAttachments: [],
        paymentProofAttachments: [],
        partnerAttachments: [],
      };
      Object.keys(newRequest).forEach(
        (k) => newRequest[k] === undefined && delete newRequest[k],
      );

      setTabbyTamaraRequests((prev) => {
        const updated = [newRequest, ...prev];
        setStorageItem("sched_tabby_tamara", updated);
        return updated;
      });

      // Sync to Firestore
      await setDoc(doc(db, "tt_requests", newRequest.id), newRequest);

      // Clear form
      setTtPatientName("");
      setTtClinicName("");
      setTtFileNumber("");
      setTtIsOldCustomer(true);
      setTtIdNumber("");
      setTtPriceWithoutTax("");
      setTtPhoneNumber("");
      setTtNotes("");
      setActiveScreenshot(null);
      setActivePhotos([]);
      setActiveLinks([]);

      // Notifications
      if (channelLabel === "call_center") {
        const socialMediaAgents = Object.entries(AGENT_LOBS)
          .filter(([name, lob]) => lob === "Chat" && name !== currentUser?.name)
          .map(([name]) => name);

        socialMediaAgents.forEach((agentName) => {
          addSystemNotification(
            "New Tabby/Tamara request. Please contact the client.",
            `${currentUser.name} (Call Center) submitted a request for ${ttPatientName} (${ttPhoneNumber}).`,
            "general",
            agentName,
            undefined,
            "tt_request",
            newRequest.id,
          );
        });
      }

      addSystemNotification(
        `New ${ttPlatform.toUpperCase()} Request`,
        `${currentUser.name} submitted a new request for ${ttPatientName} (${ttPhoneNumber})`,
        "general",
        "tl",
        undefined,
        "tt_request",
        newRequest.id,
      );

      setSubmissionConfirmation({
        title: "Fintech Request Confirmed! ",
        message: `Your ${ttPlatform === "tabby" ? "Tabby" : ttPlatform === "tamara" ? "Tamara" : "One Time Payment"} link request was successfully filed. The Team Leader has been notified to generate the installment link. Do not submit this request twice.`,
        type: "fintech_request",
        referenceId: newRequest.id,
      });
      window.scrollTo({ top: 0, behavior: "smooth" });
    } catch (err) {
      console.error(err);
      toast.error("Fintech error: " + (err.message || err));
    } finally {
      setIsFormSubmitting(false);
    }
  };

  const handleConfirmTabbyTamara = (
    requestId: string,
    paymentLink: string,
    tlNotes?: string,
    tlLinks?: string,
    status: "confirmed" | "rejected" = "confirmed",
    tlPhotos?: string[],
    tlSupportingLinks?: string[],
  ) => {
    if (!currentUser) return;
    const updated = tabbyTamaraRequests.map((r) => {
      if (r.id === requestId) {
        const isRejected = status === "rejected";
        const isAlreadyConfirmed = r.status === "confirmed";

        const existingLinks = Array.isArray((r as any).paymentLinks)
          ? (r as any).paymentLinks
          : r.paymentLink
            ? [r.paymentLink]
            : [];
        let updatedLinks = [...existingLinks];
        if (paymentLink && !updatedLinks.includes(paymentLink)) {
          updatedLinks.push(paymentLink);
        }

        const newWorkflowStatus: TTWorkflowStatus = isRejected
          ? "rejected"
          : isAlreadyConfirmed
            ? r.workflowStatus || "tl_link_ready"
            : "tl_link_ready";

        const activityText = isRejected
          ? `${currentUser.name} (TL) rejected this request. Notes: ${tlNotes || ""}`
          : isAlreadyConfirmed
            ? `${currentUser.name} (TL) added an additional payment link: ${paymentLink}.`
            : `${currentUser.name} (TL) processed the request. Payment link attached. Workflow set to: Link Ready.`;

        const activityEntry = {
          id: "act_" + Math.random().toString(36).substr(2, 9),
          senderName: "System",
          authorId: "system",
          authorRole: "system",
          text: activityText,
          createdAt: new Date().toISOString(),
          attachments: [],
          links: [],
        };

        const existingReplies = Array.isArray(r.replies) ? r.replies : [];

        const updatedReq = {
          ...r,
          status: isAlreadyConfirmed ? ("confirmed" as const) : status,
          confirmedAt: r.confirmedAt || new Date().toISOString(),
          confirmedBy: r.confirmedBy || currentUser.name,
          paymentLink: paymentLink || r.paymentLink || null,
          paymentLinks: updatedLinks,
          tlNotes: tlNotes || r.tlNotes || null,
          tlLinks: tlLinks || r.tlLinks || undefined,
          tlPhotos: tlPhotos || r.tlPhotos || [],
          tlSupportingLinks: tlSupportingLinks || [],
          workflowStatus: newWorkflowStatus,
          replies: [...existingReplies, activityEntry],
          updatedAt: new Date().toISOString(),
        };
        // Sync to Firestore
        setDoc(doc(db, "tt_requests", r.id), updatedReq).catch((e) =>
          console.error("TT Confirm Error:", e),
        );

        const notifyTarget = r.assignedToName || r.agentName;

        addSystemNotification(
          status === "confirmed"
            ? ` Payment Link Ready`
            : ` Fintech Request Rejected`,
          status === "confirmed"
            ? `Your ${r.platform} request for ${r.patientName} has been confirmed. ${tlNotes ? `Notes: ${tlNotes}` : ""}`
            : `Your ${r.platform} request for ${r.patientName} has been rejected. ${tlNotes ? `Notes: ${tlNotes}` : ""}`,
          "general",
          notifyTarget,
          undefined,
          "tt_request",
          r.id,
        );

        // If submitter is Call Center, notify all Chat agents to contact patient
        if (status === "confirmed" && paymentLink) {
          const submitterLOB = getAgentLOB(r.agentName) || "Unknown";
          if (submitterLOB === "Call Center") {
            const socialMediaAgents = Object.entries(AGENT_LOBS)
              .filter(([name, lob]) => lob === "Chat")
              .map(([name]) => name);

            socialMediaAgents.forEach((agentName) => {
              addSystemNotification(
                "💳 Payment Link Ready — Please Contact Patient",
                `TL ${currentUser.name} confirmed a ${r.platform?.toUpperCase()} request.\n` +
                  `Patient: ${r.patientName}\n` +
                  `Phone: ${(r.phoneNumber || "").replace(/^0+/, "")} (starts from 5)\n` +
                  `Clinic: ${r.clinicName}\n` +
                  `Payment Link: ${paymentLink}\n` +
                  `${tlNotes ? "Notes: " + tlNotes : ""}`,
                "general",
                agentName,
                undefined,
                "tt_request",
                requestId,
              );
            });
          }
        }

        return updatedReq;
      }
      return r;
    });

    setTabbyTamaraRequests(updated);
    setStorageItem("sched_tabby_tamara", updated);
    if (status === "confirmed") {
      toast.success(
        "Request successfully confirmed with feedback! Submitting agent was notified.",
      );
    } else {
      toast.success("Request successfully marked as rejected with notes!");
    }
  };

  const handleAssignRecord = async (
    recordId: string,
    collectionName: string,
    toAgent: string,
    recordType: string,
    fromAgent: string,
  ) => {
    if (!currentUser) return;
    try {
      const assigneeId =
        "usr_" + toAgent.replace(/[^a-zA-Z0-9]/g, "").toLowerCase();
      let entityType = collectionName;
      if (collectionName === "tt_complaints") entityType = "tt_complaint";
      else if (collectionName === "tt_requests") entityType = "tt_request";
      else if (collectionName === "client_comms") entityType = "client_comm";
      else if (collectionName === "inquiries") entityType = "inquiry";

      // Central assignment service call
      const success = await assignCase(
        entityType,
        recordId,
        { id: assigneeId, name: toAgent },
        currentUser,
      );

      if (!success) {
        toast.error("Failed to assign — please try again.");
        return;
      }

      // Update local state based on collectionName
      if (collectionName === "inquiries") {
        setInquiries((prev) =>
          prev.map((i) =>
            i.id === recordId ? { ...i, assignedToName: toAgent, assignedToId: assigneeId } : i,
          ),
        );
      } else if (collectionName === "tt_requests") {
        setTabbyTamaraRequests((prev) =>
          prev.map((r) =>
            r.id === recordId ? { ...r, assignedToName: toAgent, assignedToId: assigneeId } : r,
          ),
        );
      } else if (collectionName === "tt_complaints") {
        setTabbyTamaraComplaints((prev) =>
          prev.map((c) =>
            c.id === recordId ? { ...c, assignedToName: toAgent, assignedToId: assigneeId } : c,
          ),
        );
      } else if (collectionName === "client_comms") {
        setClientComms((prev) =>
          prev.map((c) =>
            c.id === recordId ? { ...c, assignedToName: toAgent, assignedToId: assigneeId } : c,
          ),
        );
      }

      // Notify assigned agent
      addSystemNotification(
        `📌 ${recordType} Assigned to You`,
        `TL ${currentUser.name} assigned a ${recordType} to you. Previously handled by ${fromAgent}. Please review and action.`,
        "general",
        toAgent,
      );
      toast.success(`Assigned to ${toAgent}!`);
    } catch (err: any) {
      console.error(err);
      toast.error("Failed to assign record.");
    }
  };

  const handleContactTabbyTamara = async (
    requestId: string,
    status: "not_contacted" | "contacted",
    notes?: string,
    screenshot?: string,
    attachments?: string[],
    clientIdAttachments?: FileAttachment[],
    paymentProofAttachments?: FileAttachment[],
    newWorkflowStatus?: TTWorkflowStatus,
  ) => {
    if (!currentUser) return;

    // Process attachments if they exist
    const processedClientIdAttachments = await processAttachments(
      clientIdAttachments,
      "tabby_tamara",
      requestId,
      "client_id",
    );

    const processedPaymentProofAttachments = await processAttachments(
      paymentProofAttachments,
      "tabby_tamara",
      requestId,
      "payment_proof",
    );

    const updated = tabbyTamaraRequests.map((r) => {
      if (r.id === requestId) {
        const derivedStatus =
          newWorkflowStatus ||
          (status === "contacted" ? "ready_for_partner" : "tl_link_ready");
        const existingReplies = Array.isArray(r.replies) ? r.replies : [];
        const activityEntries: any[] = [];

        if (status === "contacted") {
          let desc = `${currentUser.name} contacted the client. Status changed to Ready for Partner.`;
          if (notes) {
            desc += ` Notes: ${notes}`;
          }
          activityEntries.push({
            id: "act_" + Math.random().toString(36).substr(2, 9),
            senderName: "System",
            authorId: "system",
            authorRole: "system",
            text: desc,
            createdAt: new Date().toISOString(),
          });
        } else {
          activityEntries.push({
            id: "act_" + Math.random().toString(36).substr(2, 9),
            senderName: "System",
            authorId: "system",
            authorRole: "system",
            text: `${currentUser.name} marked contact status as UNDO. Status changed back to Link Ready / Awaiting Client Contact.`,
            createdAt: new Date().toISOString(),
          });
        }

        const updatedReq = {
          ...r,
          customerContacted: status,
          contactedAt:
            status === "contacted" ? new Date().toISOString() : undefined,
          agentContactNotes: notes || r.agentContactNotes || "",
          paymentScreenshot: screenshot || r.paymentScreenshot || null,
          attachments:
            attachments && attachments.length > 0
              ? [...(r.attachments || []), ...attachments]
              : r.attachments || [],
          clientIdAttachments:
            processedClientIdAttachments.length > 0
              ? processedClientIdAttachments
              : r.clientIdAttachments || [],
          paymentProofAttachments:
            processedPaymentProofAttachments.length > 0
              ? processedPaymentProofAttachments
              : r.paymentProofAttachments || [],
          workflowStatus: derivedStatus,
          replies: [...existingReplies, ...activityEntries],
          updatedAt: new Date().toISOString(),
        };

        // Notify TL/support when ready_for_partner
        if (derivedStatus === "ready_for_partner") {
          addSystemNotification(
            `Fintech Ready for Partner`,
            `${currentUser.name} completed client contact and uploaded materials for ${r.patientName}. Request is ready for partner.`,
            "general",
            "tl",
            undefined,
            "tt_request",
            r.id,
          );
        }

        // Sync to Firestore
        setDoc(doc(db, "tt_requests", r.id), updatedReq).catch((e) =>
          console.error("TT Update Contact Error:", e),
        );
        return updatedReq;
      }
      return r;
    });

    setTabbyTamaraRequests(updated);
    setStorageItem("sched_tabby_tamara", updated);
    if (status === "contacted") {
      toast.success("Case marked as contacted and uploaded!");
    } else {
      toast.success("Undo contact status.");
    }
  };

  const handleDeleteTabbyTamara = (requestId: string) => {
    showConfirm(
      "Delete Request",
      "Are you sure you want to delete this Tabby/Tamara request?",
      "Delete",
      "bg-rose-700 hover:bg-rose-600",
      () => {
        const updated = tabbyTamaraRequests.filter((r) => r.id !== requestId);
        setTabbyTamaraRequests(updated);
        setStorageItem("sched_tabby_tamara", updated);

        // Sync to Firestore
        deleteDoc(doc(db, "tt_requests", requestId)).catch((e) =>
          console.error("TT Delete Error:", e),
        );
      },
    );
  };

