  const handleResetAllData = async () => {
    if (!isGlobalAdmin) {
      toast.error("Unauthorized access.");
      return;
    }

    showConfirm(
      "Reset All Data",
      "This will permanently wipe all local data. This cannot be undone.",
      "Yes, Wipe All",
      "bg-rose-700 hover:bg-rose-600",
      async () => {
        setIsSyncingCalendar(true); // Reusing sync state for loading
        try {
          // 1. Delete Firestore Collections
          const collectionsToWipe = [
            "schedules",
            "scheduling_requests",
            "inquiries",
            "client_comms",
            "cases",
            "timelogs",
            "announcements",
            "orders",
            "tt_requests",
            "tt_complaints",
            "qa_scores",
            "notifications",
            "tl_shift_logs",
            "attendance_records",
            "tl_feedbacks",
            "todos",
          ];

          for (const colName of collectionsToWipe) {
            const q = query(collection(db, colName));
            const snapshot = await getDocs(q);
            const batch = writeBatch(db);
            snapshot.docs.forEach((doc) => {
              batch.delete(doc.ref);
            });
            await batch.commit();
            console.log(
              `Wiped collection "${colName}": Deleted ${snapshot.size} documents.`,
            );
          }

          // Also clear all local data
          localStorage.clear();

          toast.success(
            "System wipe successful. All organizational data has been reset.",
          );
          window.location.reload(); // Hard refresh to clear all local states
        } catch (error) {
          console.error("Reset failed:", error);
          toast.error("Reset failed. Check console for details.");
        } finally {
          setIsSyncingCalendar(false);
        }
      },
    );
    return;
  };

  const handleCloseAllCases = async () => {
    if (!isGlobalAdmin) {
      toast.error(
        "Unauthorized: This action is restricted to Hesham Sobhy (h.sobhy).",
      );
      return;
    }

    showConfirm(
      "Close All Cases & SLAs",
      "Are you absolutely sure you want to close ALL cases across all SLA departments (Tabby, Tamara, Complaints, General Inquiries, Client Communications, and general CRM Cases)?",
      "Close All Cases",
      "bg-rose-700 hover:bg-rose-600",
      async () => {
        setIsSyncingCalendar(true);
        try {
          const now = new Date().toISOString();
          const closedBy = currentUser?.name || "Hesham Sobhy";
          const promises: Promise<any>[] = [];

          // 1. inquiries
          const openInqs = inquiries.filter((i) => i.status !== "closed");
          openInqs.forEach((inq) => {
            promises.push(
              updateDoc(doc(db, "inquiries", inq.id), {
                status: "closed",
                closedBy,
                closedAt: now,
              }),
            );
          });

          // 2. tt_requests (Tabby & Tamara Requests)
          const openTTRequests = tabbyTamaraRequests.filter(
            (r) =>
              r.workflowStatus !== "completed" &&
              r.workflowStatus !== "rejected",
          );
          openTTRequests.forEach((req) => {
            promises.push(
              updateDoc(doc(db, "tt_requests", req.id), {
                workflowStatus: "completed",
                status: "confirmed",
                confirmedBy: closedBy,
                confirmedAt: now,
                updatedAt: now,
              }),
            );
          });

          // 3. tt_complaints (Tabby & Tamara Complaints)
          const openTTComplaints = tabbyTamaraComplaints.filter(
            (c) => c.status !== "closed",
          );
          openTTComplaints.forEach((comp) => {
            const sysActivity = {
              id: "act_" + Math.random().toString(36).substring(2, 11),
              senderName: "System",
              authorId: "system",
              text: `${closedBy} executed SLA bulk-close tool to close this ticket.`,
              createdAt: now,
            };
            promises.push(
              updateDoc(doc(db, "tt_complaints", comp.id), {
                status: "closed",
                customerContacted: "contacted",
                contactedAt: now,
                tlHandledBy: closedBy,
                tlHandledAt: now,
                replies: arrayUnion(sysActivity),
              }),
            );
          });

          // 4. client_comms (Client Communication Requests)
          const openClientComms = (clientComms || []).filter(
            (cc) => cc.status !== "contacted",
          );
          openClientComms.forEach((cc) => {
            promises.push(
              updateDoc(doc(db, "client_comms", cc.id), {
                status: "contacted",
                handledBy: closedBy,
                handledAt: now,
              }),
            );
          });

          // 5. cases (general CRM Cases)
          const openCases = cases.filter((c) => c.status !== "closed");
          openCases.forEach((c) => {
            promises.push(
              updateDoc(doc(db, "cases", c.id), {
                status: "closed",
              }),
            );
          });

          if (promises.length === 0) {
            toast.info("There are no open cases or SLAs to close.");
            return;
          }

          await Promise.all(promises);
          toast.success(
            `Successfully closed all ${promises.length} open cases and SLAs across all channels!`,
          );
        } catch (error: any) {
          console.error("Failed to bulk close all cases:", error);
          toast.error("Failed to bulk close all cases: " + error.message);
        } finally {
          setIsSyncingCalendar(false);
        }
      },
    );
  };

