  const getShiftBadgeStyle = (label: string) => {
    if (!label)
      return {
        bg: "bg-slate-500/10 text-slate-400 border-slate-500/20",
        display: "Not Scheduled",
      };
    const norm = label.toLowerCase();
    if (
      norm.includes("morning") ||
      norm.includes("am") ||
      norm.includes("07:") ||
      norm.includes("08:") ||
      norm === "a" ||
      norm === "morning shift"
    ) {
      return {
        bg: "bg-sky-500/15 text-sky-300 border-sky-500/25",
        display: "Morning",
      };
    }
    if (
      norm.includes("afternoon") ||
      norm.includes("pm") ||
      norm.includes("12:") ||
      norm.includes("13:") ||
      norm.includes("14:") ||
      norm === "b" ||
      norm === "afternoon shift"
    ) {
      return {
        bg: "bg-amber-500/15 text-amber-300 border-amber-500/25",
        display: "Afternoon",
      };
    }
    if (
      norm.includes("night") ||
      norm.includes("22:") ||
      norm.includes("23:") ||
      norm.includes("00:") ||
      norm.includes("graveyard") ||
      norm === "c" ||
      norm === "night shift"
    ) {
      return {
        bg: "bg-purple-500/15 text-purple-300 border-purple-500/25",
        display: "Night",
      };
    }
    if (norm === "not scheduled" || norm === "unassigned") {
      return {
        bg: "bg-slate-500/10 text-slate-400 border-slate-500/20",
        display: "Not Scheduled",
      };
    }
    if (
      norm.includes("off") ||
      norm.includes("leave") ||
      norm.includes("al") ||
      norm.includes("sl") ||
      norm === "o" ||
      norm === "r"
    ) {
      return {
        bg: "bg-slate-500/10 text-slate-400 border-slate-500/20",
        display: "Off Day",
      };
    }
    return {
      bg: "bg-slate-500/10 text-slate-400 border-slate-500/20",
      display: label,
    };
  };

